mapper.select:
SELECT
COALESCE(SUM(a.num), 0) AS num
FROM (
SELECT
COUNT(DISTINCT user_id) AS num
FROM
lkt_mch_browse
WHERE
store_id = #{model.store_id}

    AND mch_id = #{model.mch_id}

GROUP BY
DATE_FORMAT(add_time, '%Y-%m-%d')
) a;

SELECT DATE_FORMAT(daily_group.date_key, '%m/%d') AS time, COALESCE(SUM(daily_group.user_count), 0) AS value FROM ( SELECT DATE(add_time) AS date_key, COUNT(DISTINCT user_id) AS user_count FROM lkt_mch_browse WHERE store_id = #{storeId}
AND FIND_IN_SET(#{mchId}, mch_id) > 0
AND add_time >= #{startDate} AND add_time <= #{endDate} GROUP BY DATE(add_time), user_id -- 按日期和用户分组，统计每个用户每天的访问记录 ) AS daily_group GROUP BY daily_group.date_key -- 按日期汇总独立用户数 ORDER BY daily_group.date_key;
